<?php
namespace App\Services\Customers; use App\Models\Customers\Customer; use App\Models\Customers\CustomerGroup; use App\Models\Customers\CustomerGroupMember; use App\Models\User; use App\Services\AuditLogger; use Illuminate\Support\Str;
class CustomerGroupService { public function __construct(private readonly AuditLogger $audit,private readonly CustomerEventService $events){} /** @param array<string,mixed> $data */ public function create(User $user,array $data):CustomerGroup{$group=CustomerGroup::create($data+['company_id'=>$user->company_id,'slug'=>Str::slug($data['slug']?:$data['name'])]);$this->audit->record('customer.group.created',$group,'Customer group created');return $group;} /** @param array<string,mixed> $data */ public function update(CustomerGroup $group,array $data):CustomerGroup{$group->update($data+['slug'=>Str::slug($data['slug']?:$group->slug)]);$this->audit->record('customer.group.updated',$group,'Customer group updated');return $group->refresh();} public function delete(CustomerGroup $group):void{$group->delete();$this->audit->record('customer.group.deleted',$group,'Customer group deleted');} public function restore(CustomerGroup $group):CustomerGroup{$group->restore();$this->audit->record('customer.group.restored',$group,'Customer group restored');return $group->refresh();} public function assign(Customer $customer,CustomerGroup $group,User $user,?string $notes=null):void{CustomerGroupMember::firstOrCreate(['company_id'=>$customer->company_id,'customer_id'=>$customer->id,'customer_group_id'=>$group->id],['assigned_at'=>now(),'assigned_by'=>$user->id,'notes'=>$notes]);$this->audit->record('customer.group.assigned',$customer,'Customer group assigned');$this->events->dispatch('customer.group.assigned',$user,$customer,['group'=>$group->name]);} }
